import{_ as i,o as n,c as p,ag as l}from"./chunks/framework.DXGyWiRo.js";const r="/images/uebung058.jpg",c=JSON.parse('{"title":"Übung Lektion 35","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/uebung35.md","filePath":"lektionen/uebung35.md"}'),t={name:"lektionen/uebung35.md"};function a(s,e,d,o,u,h){return n(),p("div",null,[...e[0]||(e[0]=[l('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="ubung-lektion-35" tabindex="-1">Übung Lektion 35 <a class="header-anchor" href="#ubung-lektion-35" aria-label="Permalink to &quot;Übung Lektion 35&quot;">​</a></h1><p>A) Bilden Sie zu den folgenden Verbformen die entsprechenden Perfektformen:</p><ol><li><p>गायन्ति । जगुर्</p></li><li><p>स्मरन्ति । सस्मरुर्</p></li><li><p>एष्यति । इयाय</p></li><li><p>गच्छन्ति । जग्मुर्</p></li><li><p>कुरुते । चक्रे</p></li><li><p>नेष्यन्ते । निन्यिरे</p></li><li><p>जायते । जज्ञे</p></li><li><p>जानाति । जज्ञौ</p></li><li><p>संस्करोति । सञ्चस्कार</p></li><li><p>पुनीते । पुपुवे</p></li><li><p>बिभ्यति । बिभ्युर्</p></li><li><p>पिपुरति । पपरुर् । पुपूरुर्</p></li><li><p>दत्ते । ददे</p></li><li><p>यजन्ते । ईजिरे</p></li><li><p>भजन्ति unregelmäßig, nach Typ Vb! भेजुर्</p></li><li><p>वक्ति । उवाच</p></li><li><p>अदधुः । दधुर्</p></li><li><p>बिभ्रते । बभ्रिरे</p></li><li><p>मरिष्यन्ति । मम्रुर्</p></li><li><p>अशक्नुवन् । शेकुर्</p></li><li><p>अवदन् । ऊदुर्</p></li><li><p>अपिबत् । पपौ</p></li><li><p>अपान् । पपुर्</p></li><li><p>अलभत । लेभे</p></li><li><p>अहन् । जघान</p></li><li><p>मन्यन्ते । मेनिरे</p></li><li><p>अक्रामन् । चक्रमुर्</p></li><li><p>अशृण्वन् । शुश्रुवुर्</p></li><li><p>मिमते । ममिरे</p></li><li><p>अपद्यत । पेदे</p></li><li><p>सुनोति ।  सुषाव</p></li><li><p>अतिष्ठत् । तस्थौ</p></li><li><p>पतिष्यन्ति । पेतुर्</p></li><li><p>अपचत् । पपाच</p></li><li><p>अजहुर् । जहुर्</p></li><li><p>धक्ष्यन्ति । देहिरे</p></li><li><p>स्तौति । तुष्टाव</p></li><li><p>तनुते । तेने</p></li><li><p>अचरत् । चचार</p></li><li><p>जुह्वति । जुहुवुर्</p></li><li><p>अहरत् । जहार</p></li></ol><p>B) Übersetzen Sie:</p><p>एकस्मिन्नेव काले क्षत्रियो महान्यष्टुमुपचक्रमे । तस्य यज्ञपशुमिन्द्रो जहार । प्रनष्टे तु पशौ दुर्ब्राह्मणः क्षत्रियमब्रवीत् । पशुर्हृतः क्षत्रियस्य दुर्नयादिति ॥१॥</p><p>Einstmals ging ein großer Kṣatriya, um zu opfern. Indra nahm sein Opfertier an. Als aber das Tier verschwunden war sprach ein böser Brahmane zum Kṣatriya: &quot;Das Tier ist wegen des schlechten Betragens des Kṣatriya verschwunden.&quot;</p><p>रामो ऽपुत्र आस । स पुत्रमियेष न तु लेभे । तस्माद्देवानीजे ब्रह्मचर्यादिव्रतानि च चकार । देवा रामस्येष्टिं शुश्रुवू रामाय चेष्टपुत्रं ददुः ॥२॥</p><p>Rāma hatte keinen Sohn. Er wünschte sich einen Sohn, bekam aber keinen. Deshalb opferte er den Götter und hielt Gelübde wie sexuelle Enthaltsamkeit und ähnliche. Die Götter hörten Rāmas Wunsch und schenkten ihm den gewünschten Sohn.</p><p>ब्राह्मण्यो यज्ञाय घृतं पेचुः । ब्राह्मणीषु पचन्तीषु ब्राह्मणा यज्ञस्थानं सञ्चस्करुः । ततः क्षत्रियाः शिवादिदेवानीजिरे ब्राह्मणाश्चेजुः ॥३॥</p><p>Die Brahmaninnen kochten für das Opfer Ghee. Während die Brahmaninnen kochten breiteten die Brahmanen den Opferplatz. Dann opferte die Kṣatriyas Śiva und den anderen Göttern als Opferherren und die Brahmanen vollzogen das Opfer im Auftrag der Kṣatriyas.</p><p>अर्हन्तः कुलबन्धनं बिभिदुर्लोभं च क्रोधं च मोहं च रुरुधुः सत्यं प्रजज्ञुर्दुःखान्मुक्ता मोक्षसुखमापुः ॥४॥</p><p>Arhants haben das familiäre Band zerbrochen, Gier, Hass und Verblendung beendet, die Wahrheit erkannt und vom Leiden Befreit das Glück der Erlösung erreicht.।</p><p>C) Wandeln Sie die Sätze der Übung B) um, indem Sie Perfekta durch Imperfekta ersetzen.</p><p>एकस्मिन्नेव काले क्षत्रियो महान्यष्टु्मुपाक्रामत । तस्य यज्ञपशुमिन्द्रो ऽहरत् ॥१॥</p><p>रामो ऽपुत्र आसीत् । स पुत्रमैच्छन्न् त्वलभत । तस्माद्देवानयजत ब्रह्मचर्यादिव्रतानि चाचरत् । देवा रामस्येष्टिमशृण्वन्रामाय चेष्टपुत्रमददुः ॥२॥</p><p>ब्राह्मण्यो यज्ञाय घृतमपचन् । ब्राह्मणीषु पचन्तीषु ब्राह्मणा यज्ञस्थानं समस्कुर्वन् । ततः क्षत्रियाः शिवादिदेवानयजन्त ब्राह्मणाश्चायजन् ॥३॥</p><p>अर्हन्तः कुलबन्धनमभिन्दंल्लोभं च क्रोधं च मोहं चारुन्धन्सत्यमजानन्दुःखान्मुक्ता मोक्षसुखमाप्नुवन् ॥४॥</p><p><img src="'+r+'" alt=""><br> Abb.: ब्राह्मणीषु पचन्तीषु ...<br> In der Nähe von Thiruvananthapuram = തിരുവനന്തപുരം<br> [Bildquelle: FriskoDude. -- <a href="http://www.flickr.com/photos/friskodude/1177242/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/friskodude/1177242/</a>. -- Zugriff am 2009-01-06. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p><p>Zu den <a href="./uebung36">Lösungen der Übungen 36 - 40</a></p>',20)])])}const g=i(t,[["render",a]]);export{c as __pageData,g as default};
